//vip.opstream17.com/20240302/1767_df938132/index.m3u8"},{"name":"19","slug":"","filename":"Người.Mẹ.Nhí.2006.E19.1080i.HDTV.MPEG2.0.H.264-[hoiMgiauten.xyz]","link_embed":"https://vip.opstream17.com/share/96a93ba89a5b5c6c226e49b88973f46e","link_m3u8":"https://vip.opstream17.com/20240302/1766_479e27d9/index.m3u8"},{"name":"20","slug":"","filename":"Người.Mẹ.Nhí.2006.E20.1080i.HDTV.MPEG2.0.H.264-[hoiMgiauten.xyz]","link_embed":"https://vip.opstream17.com/share/f48c04ffab49ff0e5d1176244fdfb65c","link_m3u8":"https://vip.opstream17.com/20240307/2036_203b29b3/index.m3u8"}]}],"time":"45 phút/tập","description":"<p><i>Câu chuyện 500 năm về trước, Uyển Lan là một yêu tinh già, có 2 con gái là Chân Trân và Khánh Du. Đến năm 2020, do đi đầu thai trễ nên bà trở thành một bé gái 10 tuổi. Để sum họp chung mái nhà, Chân Trân đành nhận Uyển Lan làm con nuôi. Bí mật này chỉ có 2 cô con gái cùng bà giúp việc Mai Liên được biết. Trớ trêu là 500 năm nay họ vẫn giữ quan hệ mẹ con, chủ tớ nên với kiếp này vẫn không có gì thay đổi. Uyển Lan bất đắc dĩ trở thành một bà mẹ nhí.</i><br><i>Bà già trong lốt trẻ em vừa ngây thơ vừa già dặn, sử dụng phép thuật đôi khi khá tùy tiện, gây những hiểu lầm đáng tiếc cho những người bình thường chung quanh. Tuy hành xử ngoài khuôn phép và trật tự thông thường của đời sống, nhưng bà mẹ vẫn giữ được phẩm chất của một bậc sinh thành. Bà luôn lo lắng hết mình cho sự an nguy, niềm vui, hạnh phúc trong cuộc đời của 2 cô con gái, dù vốn dĩ trong kiếp sống hiện tại họ hơn tuổi của mình.</i></p>","tmdb":{"type":null,"id":"","season":null,"vote_average":0,"vote_count":0},"modified":"2024-03-08T10:32:35.000Z"},{"id":"65e48c39e5f40e2ffe9b48b0","_id":"65e48c39e5f40e2ffe9b48b0","title":"Sắc Dục Hồi Sinh","origin_name":"Poor Things","slug":"sac-duc-hoi-sinh","year":2023,"type":"single","genre":[{"id":"620a2282e0fc277084dfd435","name":"Viễn Tưởng","slug":"vien-tuong"},{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620a221de0fc277084dfd1c1